function BookCard3D({ book, onClick, theme }) {
  const t = THEMES[theme];
  const [tilt, setTilt] = useState({ x: 0, y: 0 });
  const [hovered, setHovered] = useState(false);
  const cardRef = useRef(null);

  const handleMouseMove = (e) => {
    const rect = cardRef.current.getBoundingClientRect();
    const cx = rect.left + rect.width / 2;
    const cy = rect.top + rect.height / 2;
    const dx = (e.clientX - cx) / (rect.width / 2);
    const dy = (e.clientY - cy) / (rect.height / 2);
    setTilt({ x: -dy * 12, y: dx * 12 });
  };

  return (
    <div
      ref={cardRef}
      onMouseMove={handleMouseMove}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => { setTilt({ x: 0, y: 0 }); setHovered(false); }}
      onClick={() => onClick(book)}
      style={{ perspective: "800px", cursor: "pointer", width: "100%" }}
    >
      <div
        style={{
          transform: `rotateX(${tilt.x}deg) rotateY(${tilt.y}deg) ${hovered ? "translateY(-8px)" : ""}`,
          transition: hovered ? "transform 0.1s ease-out" : "transform 0.5s ease-out",
          transformStyle: "preserve-3d",
          borderRadius: "8px",
          overflow: "hidden",
          boxShadow: hovered
            ? `0 25px 50px rgba(0,0,0,0.7), 0 0 30px ${book.accent}44`
            : "0 10px 30px rgba(0,0,0,0.5)",
        }}
      >
        {/* Cover image */}
        <div style={{ position: "relative", aspectRatio: "2 / 3", overflow: "hidden" }}>
          {book.coverImage ? (
            <img
              src={book.coverImage}
              alt={book.title}
              style={{ width: "100%", height: "100%", objectFit: "cover", display: "block", transition: "transform 0.4s ease", transform: hovered ? "scale(1.05)" : "scale(1)" }}
            />
          ) : (
            <div style={{ width: "100%", height: "100%", background: `linear-gradient(135deg, ${book.color}, ${book.spine})`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: "48px" }}>📖</div>
          )}
          {/* Spine overlay */}
          <div style={{ position: "absolute", left: 0, top: 0, width: "5px", height: "100%", background: `linear-gradient(180deg, ${book.accent}, ${book.accent}88)` }} />
          {/* Badge */}
          {book.badge && (
            <div style={{ position: "absolute", top: "10px", right: "10px", background: "linear-gradient(135deg, #C9A84C, #a07830)", color: "#000", fontSize: "9px", fontWeight: "900", letterSpacing: "1px", padding: "4px 8px", borderRadius: "4px", textTransform: "uppercase" }}>
              {book.badge}
            </div>
          )}
          {/* Hover overlay */}
          {hovered && (
            <div style={{ position: "absolute", inset: 0, background: "rgba(0,0,0,0.45)", display: "flex", alignItems: "center", justifyContent: "center" }}>
              <span style={{ color: "#fff", fontWeight: "700", fontSize: "14px", letterSpacing: "1px", textTransform: "uppercase", border: "1px solid rgba(255,255,255,0.6)", padding: "8px 18px", borderRadius: "4px" }}>View Details</span>
            </div>
          )}
        </div>
        {/* Bottom bar */}
        <div style={{ background: hovered ? book.accent : t.cardBg, padding: "13px 16px", display: "flex", justifyContent: "space-between", alignItems: "center", transition: "background 0.3s ease" }}>
          <div>
            <div style={{ color: hovered ? "#000" : t.text, fontSize: "13px", fontWeight: "700", lineHeight: "1.2", transition: "color 0.3s" }}>{book.title.length > 28 ? book.title.slice(0, 28) + "…" : book.title}</div>
            <div style={{ color: hovered ? "rgba(0,0,0,0.6)" : t.textFainter, fontSize: "10px", marginTop: "2px", transition: "color 0.3s" }}>{book.category}</div>
          </div>
          <div style={{ color: hovered ? "#000" : "#C9A84C", fontSize: "18px", fontWeight: "800", transition: "color 0.3s", flexShrink: 0, marginLeft: "8px" }}>${book.price}</div>
        </div>
      </div>
    </div>
  );
}

function BookModal({ book, onClose, theme, supportEmail }) {
  const t = THEMES[theme];
  useEffect(() => {
    document.body.style.overflow = "hidden";
    return () => { document.body.style.overflow = ""; };
  }, []);

  const handlePurchase = () => {
    if (book.paymentLink) {
      window.open(book.paymentLink, "_blank", "noopener,noreferrer");
    }
  };

  return (
    <div onClick={onClose} style={{ position: "fixed", inset: 0, background: t.overlay, backdropFilter: "blur(10px)", zIndex: 1000, display: "flex", alignItems: "center", justifyContent: "center", padding: "20px", animation: "fadeIn 0.2s ease" }}>
      <div onClick={(e) => e.stopPropagation()} style={{ background: t.cardBg, border: `1px solid ${t.borderStrong}`, borderRadius: "16px", width: "100%", maxWidth: "760px", maxHeight: "90vh", overflow: "auto", animation: "slideUp 0.3s ease" }}>
          <div>
            {/* Modal header with cover */}
            <div style={{ display: "flex", gap: "0", borderRadius: "16px 16px 0 0", overflow: "hidden", borderBottom: `1px solid ${t.border}` }}>
              {/* Cover panel */}
              <div style={{ width: "160px", flexShrink: 0, position: "relative" }}>
                {book.coverImage ? (
                  <img src={book.coverImage} alt={book.title} style={{ width: "100%", height: "100%", objectFit: "cover", display: "block", minHeight: "200px" }} />
                ) : (
                  <div style={{ width: "100%", height: "200px", background: `linear-gradient(135deg, ${book.color}, ${book.spine})`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: "48px" }}>📖</div>
                )}
              </div>
              {/* Info panel */}
              <div style={{ flex: 1, background: `linear-gradient(135deg, ${book.color}ee, ${t.cardBg})`, padding: "28px 28px 28px 24px", display: "flex", flexDirection: "column", justifyContent: "center", position: "relative" }}>
                {book.badge && (
                  <span style={{ background: "linear-gradient(135deg, #C9A84C, #a07830)", color: "#000", fontSize: "9px", fontWeight: "900", letterSpacing: "1.5px", padding: "3px 10px", borderRadius: "4px", display: "inline-block", marginBottom: "10px", textTransform: "uppercase", alignSelf: "flex-start" }}>{book.badge}</span>
                )}
                <span style={{ background: `${book.accent}20`, color: book.accent, fontSize: "10px", fontWeight: "700", letterSpacing: "1.5px", textTransform: "uppercase", padding: "3px 10px", borderRadius: "20px", display: "inline-block", marginBottom: "10px", border: `1px solid ${book.accent}44`, alignSelf: "flex-start" }}>{book.category}</span>
                <h2 style={{ color: "#fff", fontFamily: "'Georgia', serif", fontSize: "20px", fontWeight: "800", marginBottom: "8px", lineHeight: "1.25" }}>{book.title}</h2>
                <p style={{ color: "rgba(255,255,255,0.5)", fontSize: "13px", marginBottom: "6px", fontStyle: "italic" }}>{book.subtitle}</p>
                <p style={{ color: "#C9A84C", fontSize: "12px", fontWeight: "600" }}>by {book.author}</p>
                <button onClick={onClose} style={{ position: "absolute", top: "14px", right: "14px", background: "rgba(255,255,255,0.12)", border: "none", color: "#fff", width: "30px", height: "30px", borderRadius: "50%", cursor: "pointer", fontSize: "15px", display: "flex", alignItems: "center", justifyContent: "center" }}>✕</button>
              </div>
            </div>

            <div style={{ padding: "26px 28px", display: "flex", flexDirection: "column", gap: "20px" }}>
              {/* Description */}
              <div>
                <h4 style={{ color: t.textFainter, fontSize: "10px", fontWeight: "700", letterSpacing: "2px", textTransform: "uppercase", marginBottom: "10px" }}>About this Book</h4>
                <p style={{ color: t.textMuted, lineHeight: "1.75", fontSize: "14px" }}>{book.description}</p>
              </div>

              {/* TOC */}
              <div>
                <h4 style={{ color: t.textFainter, fontSize: "10px", fontWeight: "700", letterSpacing: "2px", textTransform: "uppercase", marginBottom: "12px" }}>Inside the Book</h4>
                <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", gap: "6px" }}>
                  {book.toc.map((ch, i) => (
                    <div key={i} style={{ display: "flex", alignItems: "flex-start", gap: "10px", padding: "9px 12px", background: `${book.accent}08`, borderRadius: "7px", border: `1px solid ${book.accent}18` }}>
                      <span style={{ color: book.accent, fontSize: "11px", fontWeight: "800", minWidth: "18px", marginTop: "1px" }}>{i + 1}</span>
                      <span style={{ color: t.textMuted, fontSize: "13px", lineHeight: "1.4" }}>{ch.replace(/^Ch\.\d+ — /, "")}</span>
                    </div>
                  ))}
                </div>
              </div>

              {/* Reviews */}
              {book.reviews && book.reviews.length > 0 && (
                <div>
                  <h4 style={{ color: t.textFainter, fontSize: "10px", fontWeight: "700", letterSpacing: "2px", textTransform: "uppercase", marginBottom: "12px" }}>Reader Reviews</h4>
                  <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(240px, 1fr))", gap: "10px" }}>
                    {book.reviews.map((r, i) => (
                      <div key={i} style={{ padding: "14px", background: t.reviewBg, borderRadius: "8px", border: `1px solid ${t.reviewBorder}` }}>
                        <div style={{ color: "#C9A84C", fontSize: "13px", marginBottom: "6px" }}>{"★".repeat(r.stars)}{"☆".repeat(5 - r.stars)}</div>
                        <p style={{ color: t.textMuted, fontSize: "13px", lineHeight: "1.6", marginBottom: "8px", fontStyle: "italic" }}>"{r.text}"</p>
                        <p style={{ color: t.textFainter, fontSize: "12px", fontWeight: "600" }}>— {r.name}</p>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {/* Purchase */}
              <div style={{ background: "rgba(201,168,76,0.05)", border: "1px solid rgba(201,168,76,0.22)", borderRadius: "12px", padding: "22px" }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "16px" }}>
                  <div>
                    <div style={{ color: t.text, fontSize: "14px", fontWeight: "600" }}>Instant Download</div>
                    <div style={{ color: t.textFainter, fontSize: "12px", marginTop: "2px" }}>PDF + EPUB · Read on any device</div>
                  </div>
                  <span style={{ color: "#C9A84C", fontSize: "32px", fontWeight: "900" }}>${book.price}</span>
                </div>
                <button onClick={handlePurchase} style={{ width: "100%", background: "linear-gradient(135deg, #C9A84C, #a07830)", color: "#000", border: "none", padding: "15px", borderRadius: "8px", fontWeight: "900", fontSize: "15px", cursor: "pointer", letterSpacing: "0.5px", transition: "opacity 0.2s", display: "flex", alignItems: "center", justifyContent: "center", gap: "8px" }} onMouseEnter={(e) => e.currentTarget.style.opacity = "0.88"} onMouseLeave={(e) => e.currentTarget.style.opacity = "1"}>
                  Buy Now on Gumroad — ${book.price} →
                </button>
                <p style={{ color: t.textFaintest, fontSize: "11px", textAlign: "center", marginTop: "10px" }}>
                  Secure checkout via Gumroad · Instant delivery · 30-day refund guarantee
                </p>
                <p style={{ color: t.textFaintest, fontSize: "11px", textAlign: "center", marginTop: "6px" }}>
                  Need help? Contact <a href={`mailto:${supportEmail}`} style={{ color: "#C9A84C", textDecoration: "none" }}>{supportEmail}</a>
                </p>
              </div>
            </div>
          </div>
      </div>
    </div>
  );
}

